const config = $json;
const thematique = (config.thematique || 'agro').toLowerCase().trim();

const MAPPINGS = {
  agro: {
    label: 'Agriculture & Développement Rural',
    secteurs: [
      { nom: 'Agriculture, Fishing & Forestry', poids: 60 },
      { nom: 'Agricultural markets, commercialization and agri-business', poids: 55 },
      { nom: 'Public Administration - Agriculture, Fishing & Forestry', poids: 45 },
      { nom: 'Irrigation and Drainage', poids: 35 }
    ],
    themes_niveau1: [
      { nom: 'Urban and Rural Development', poids: 40, seuil_min_pct: 50 },
      { nom: 'Environment and Natural Resource Management', poids: 25, seuil_min_pct: 40 }
    ],
    sous_themes: [
      { nom: 'Rural Development', poids: 40, seuil_min_pct: 40 },
      { nom: 'Nutrition and Food Security', poids: 35, seuil_min_pct: 25 },
      { nom: 'Renewable Natural Resources Asset Management', poids: 25, seuil_min_pct: 30 },
      { nom: 'Water Resource Management', poids: 15, seuil_min_pct: 40 }
    ]
  },
  environnement: {
    label: 'Environnement & Ressources Naturelles',
    secteurs: [
      { nom: 'Other Water Supply, Sanitation and Waste Management', poids: 40 },
      { nom: 'Public Administration - Water, Sanitation and Waste Management', poids: 35 }
    ],
    themes_niveau1: [
      { nom: 'Environment and Natural Resource Management', poids: 60, seuil_min_pct: 30 }
    ],
    sous_themes: [
      { nom: 'Renewable Natural Resources Asset Management', poids: 45, seuil_min_pct: 25 },
      { nom: 'Climate change', poids: 40, seuil_min_pct: 25 },
      { nom: 'Disaster Risk Management', poids: 25, seuil_min_pct: 25 },
      { nom: 'Water Resource Management', poids: 20, seuil_min_pct: 30 }
    ]
  },
  energy: {
    label: 'Energie',
    secteurs: [
      { nom: 'Energy Transmission and Distribution', poids: 65 },
      { nom: 'Oil and Gas', poids: 50 }
    ],
    themes_niveau1: [
      { nom: 'Environment and Natural Resource Management', poids: 30, seuil_min_pct: 40 },
      { nom: 'Private Sector Development', poids: 20, seuil_min_pct: 50 }
    ],
    sous_themes: [
      { nom: 'Energy', poids: 60, seuil_min_pct: 30 },
      { nom: 'Renewable Natural Resources Asset Management', poids: 30, seuil_min_pct: 30 },
      { nom: 'Climate change', poids: 15, seuil_min_pct: 30 }
    ]
  },
  eau: {
    label: 'Eau & Assainissement',
    secteurs: [
      { nom: 'Water Supply', poids: 65 },
      { nom: 'Sanitation', poids: 55 },
      { nom: 'Other Water Supply, Sanitation and Waste Management', poids: 50 },
      { nom: 'Irrigation and Drainage', poids: 40 }
    ],
    themes_niveau1: [
      { nom: 'Urban and Rural Development', poids: 30, seuil_min_pct: 50 },
      { nom: 'Environment and Natural Resource Management', poids: 25, seuil_min_pct: 30 }
    ],
    sous_themes: [
      { nom: 'Water Resource Management', poids: 55, seuil_min_pct: 25 },
      { nom: 'Disaster Risk Management', poids: 25, seuil_min_pct: 25 },
      { nom: 'Rural Development', poids: 15, seuil_min_pct: 40 }
    ]
  }
};

const criteria = MAPPINGS[thematique] || MAPPINGS['agro'];

return {
  json: {
    criteria,
    thematique,
    pays: config.pays,
    top_local: config.top_local,
    top_regional: config.top_regional,
    top_international: config.top_international,
    annees: config.annees,
    seuil_projet: config.seuil_projet,
    sheet_id: config.sheet_id
  }
};

const criteriaItem = $('Mapping Thématique').first().json;
const criteria = criteriaItem.criteria;
const pays = criteriaItem.pays;
const annees = criteriaItem.annees || 3;
const seuilProjet = criteriaItem.seuil_projet || 55;
const topLocal = criteriaItem.top_local || 30;
const topRegional = criteriaItem.top_regional || 20;
const topIntl = criteriaItem.top_international || 10;
const thematique = criteriaItem.thematique;
const sheetId = criteriaItem.sheet_id;

const projects = $('Lire WB_Projects').all().map(i => i.json);
const members = $('Lire Members').all().map(i => i.json);
const awards = $('Lire WB_Awards').all().map(i => i.json);

// ── Corrections manuelles ──
const corrections = $('Lire Corrections').all().map(i => i.json);
const forceExclude = new Set(corrections.filter(c => c.Action === 'force_exclude').map(c => String(c.Nom || '').trim()));
const forceCompany = new Set(corrections.filter(c => c.Action === 'force_company').map(c => String(c.Nom || '').trim()));
const forceExpert  = new Set(corrections.filter(c => c.Action === 'force_expert').map(c => String(c.Nom || '').trim()));

// ── Mapping tags par thématique ──
const TAG_WEIGHTS = {
  agro:          { agro: 30, consulting: 10, env: 10 },
  environnement: { env: 30, consulting: 10, agro: 10 },
  energy:        { energy: 30, consulting: 10, env: 10 },
  eau:           { env: 20, infra: 20, consulting: 10 },
  infra:         { infra: 30, consulting: 10, energy: 10 },
};
const tagWeights = TAG_WEIGHTS[thematique] || TAG_WEIGHTS['agro'];
const primaryTag = Object.entries(tagWeights).sort((a,b) => b[1] - a[1])[0][0];

// ── Score thématique projet ──
function parsePct(text, theme) {
  if (!text) return 0;
  const re = new RegExp(theme.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\s*\\((\\d+)%\\)');
  const m = String(text).match(re);
  return m ? parseInt(m[1]) : 0;
}

function scoreProject(project) {
  let score = 0;
  const sector = String(project.sector_primary || '').toLowerCase();
  const themesAll = String(project.themes_all || '');
  const subThemes = String(project.sub_themes || '');
  for (const s of (criteria.secteurs || [])) {
    if (sector.includes(s.nom.toLowerCase())) { score += s.poids; break; }
  }
  for (const t of (criteria.themes_niveau1 || [])) {
    const pct = parsePct(themesAll, t.nom);
    if (pct >= (t.seuil_min_pct || 0)) score += Math.round(t.poids * pct / 100);
  }
  for (const s of (criteria.sous_themes || [])) {
    const pct = parsePct(subThemes, s.nom);
    if (pct >= (s.seuil_min_pct || 0)) score += Math.round(s.poids * pct / 100);
  }
  return Math.min(score, 100);
}

const projectScores = {};
for (const p of projects) projectScores[p.project_id] = scoreProject(p);

const relevantProjectIds = new Set(
  Object.entries(projectScores).filter(([,s]) => s >= seuilProjet).map(([id]) => id)
);

const retainedProjects = projects
  .filter(p => relevantProjectIds.has(p.project_id))
  .map(p => ({ name: p.project_name, id: p.project_id, score: projectScores[p.project_id] }))
  .sort((a,b) => b.score - a.score);

const cutoffDate = new Date();
cutoffDate.setFullYear(cutoffDate.getFullYear() - annees);

const awardsMap = {};
for (const a of awards) awardsMap[a.award_id] = a;

const relevantAwardIds = new Set(
  awards.filter(a =>
    a.place_of_performance === pays &&
    relevantProjectIds.has(a.project_id) &&
    new Date(a.publication_date) >= cutoffDate &&
    String(a.cpv_category).toLowerCase() === 'consulting'
  ).map(a => a.award_id)
);

// ── Détection personne physique ──
const CORPORATE_WORDS = [
  'sarl','sas','eurl','ltd','llc','inc','gmbh','spa','suarl',
  'cabinet','consulting','conseil','consult',
  'group','groupe','ong','ngo','association','fondation',
  'bureau','agence','agency','institute','institut',
  'company','entreprise','firm',
  'ingenierie','ingenerie','engineering','ingenieurs','ingénieurs',
  'international','africa','afrique','global',
  'services','service','solutions','solution',
  'management','development','développement',
  'environnement','environment','technologie','technology','tech',
  'centre','center','partners','advisory','capital','holding',
  'avocats','worldwide','wolrdwide','limited','network',
  'organisation','organization',
  'energie','energy','ecopop','sahel',
  'veolia','thornton','haskoning','artelia','antea','seureca',
  'transcom','hannon','sofreco','ginger','sgi','tractebel',
  'idev','hydroconseil','studi','nodalis','comete',
  'luxembourg','terre','ocean','tpa','ifc','berd','pmu',
  'senegal','sénégal','mali','togo','niger','guinee','guinea',
  'taylor','wessing','setec','motion','zoom','hydro',
  'ums','aps','bceao','brvm','cira','ccadd','gtah',
  'egis','transport','villes','routes',
  'forvis','mazars','deloitte','pwc','kpmg','ernst',
  'ccm','brl','iram','gfa','niras','helvetas','sweco',
];

function toTitleCase(str) {
  return str.trim().toLowerCase().replace(/(?:^|\s)\S/g, c => c.toUpperCase());
}

function isPhysicalPerson(name) {
  if (!name) return false;
  const nl = name.toLowerCase().trim();
  if (CORPORATE_WORDS.some(w => nl.includes(w))) return false;
  if (/\d/.test(name)) return false;
  if (/[&+\/\(\)\.\,\_\@\#]/.test(name)) return false;
  const wordsRaw = name.trim().split(/\s+/);
  const allCaps = wordsRaw.every(w => w === w.toUpperCase() && w.length <= 4);
  if (allCaps && wordsRaw.length <= 2) return false;
  const normalized = toTitleCase(name);
  const words = normalized.split(/\s+/);
  if (words.length < 2 || words.length > 5) return false;
  for (const w of words) {
    if (!/^[A-ZÀÂÄÉÈÊËÎÏÔÙÛÜÇ][a-zA-ZàâäéèêëîïôùûüçÀÂÄÉÈÊËÎÏÔÙÛÜÇ'\-]+$/.test(w)) return false;
    if (w.length < 2) return false;
  }
  return true;
}

function isNGO(name) {
  if (!name) return false;
  const nl = name.toLowerCase();
  return /\bong\b|\bngo\b|^ong |^ngo | ong$| ngo$|association|fondation|réseau|reseau|\baid\b|secours|relief|\bcare\b|oxfam|world.vision|croix.rouge|sans.fronti/.test(nl);
}

// ── Zones ──
const PAYS_NAMES = { 'SN': 'Senegal', 'CI': "Cote d'Ivoire", 'BF': 'Burkina Faso', 'ML': 'Mali', 'TG': 'Togo', 'BJ': 'Benin', 'NE': 'Niger', 'GN': 'Guinea', 'MR': 'Mauritania', 'GH': 'Ghana' };
const paysName = PAYS_NAMES[pays] || pays;
const AFRIQUE_ALL = ['Mali','Togo','Benin','Guinea','Burkina Faso',"Cote d'Ivoire",'Niger','Mauritania','Ghana','Gambia','Guinea-Bissau','Sierra Leone','Liberia','Senegal','Morocco','Tunisia','Algeria','South Africa','Cameroon','Ethiopia','Kenya','Rwanda','Madagascar','Nigeria','Tanzania','Angola','Gabon','Chad','Uganda','Egypt'];

function normalizeCountry(str) {
  return str.trim().normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
}

function classifyZone(country) {
  if (!country) return 'unknown';
  const c = normalizeCountry(country);
  const paysNorm = normalizeCountry(paysName);
  const afriqueNorm = AFRIQUE_ALL.map(normalizeCountry);
  if (c === paysNorm) return 'local';
  if (afriqueNorm.includes(c)) return 'regional';
  return 'international';
}

// ── Fonction score tag ──
function scoreTag(grp) {
  let score = 0;
  for (const m of grp) {
    const a = awardsMap[m.award_id];
    if (!a) continue;
    const tags = String(a.tags || '').toLowerCase().split(',').map(t => t.trim());
    for (const tag of tags) {
      if (tagWeights[tag]) score += tagWeights[tag];
    }
  }
  return Math.min(score, 50); // plafond 50
}

// ── Scoring membres ──
const now = new Date();
const memberGroups = {};
for (const m of members) {
  if (!relevantAwardIds.has(m.award_id)) continue;
  if (String(m.member_name || '').match(/^GROUPEMENT\s+/i)) continue;
  const name = m.member_name;
  if (!name) continue;
  if (!memberGroups[name]) memberGroups[name] = [];
  memberGroups[name].push(m);
}

const scored = [];
const experts = [];

for (const [name, grp] of Object.entries(memberGroups)) {

  if (forceExclude.has(name)) continue;

  if (forceExpert.has(name)) {
    for (const m of grp) {
      const a = awardsMap[m.award_id];
      if (!a) continue;
      experts.push({ expert: name, pays_expert: m.member_country || '', date_award: a.publication_date || '', mission: a.title || '', valeur: a.award_value ? `${parseFloat(a.award_value).toLocaleString('fr-FR')} ${a.currency}` : 'N/A', projet_bm: a.buyer_name || '', methode: a.procurement_method || '', url: a.source_url || '' });
    }
    continue;
  }

  const treatAsCompany = forceCompany.has(name);

  if (!treatAsCompany && isPhysicalPerson(name)) {
    for (const m of grp) {
      const a = awardsMap[m.award_id];
      if (!a) continue;
      experts.push({ expert: name, pays_expert: m.member_country || '', date_award: a.publication_date || '', mission: a.title || '', valeur: a.award_value ? `${parseFloat(a.award_value).toLocaleString('fr-FR')} ${a.currency}` : 'N/A', projet_bm: a.buyer_name || '', methode: a.procurement_method || '', url: a.source_url || '' });
    }
    continue;
  }

  if (!treatAsCompany && isNGO(name)) continue;

  // ── Filtre éligibilité — au moins 1 award avec le tag principal ──
  const hasPrimaryTag = grp.some(m => {
    const a = awardsMap[m.award_id];
    if (!a) return false;
    const tags = String(a.tags || '').toLowerCase().split(',').map(t => t.trim());
    return tags.includes(primaryTag);
  });
  if (!hasPrimaryTag) continue;

  // ── Scoring société ──
  const zone = classifyZone(grp[0].member_country);
  const nAwards = grp.length;
  const dates = grp.map(m => new Date(m.publication_date)).filter(d => !isNaN(d));
  const lastAward = dates.length ? new Date(Math.max(...dates)) : null;
  const daysSince = lastAward ? (now - lastAward) / 86400000 : 9999;

  let recency = 1;
  if (daysSince <= 180) recency = 10;
  else if (daysSince <= 365) recency = 7;
  else if (daysSince <= 730) recency = 4;

  const nProjects = new Set(grp.map(m => m.project_id)).size;
  const volume = Math.min(nProjects * 5 + nAwards * 2, 20);
  const nLocal = grp.filter(m => m.place_of_performance === pays).length;
  const geo = Math.min(nLocal * 4, 20);
  const scoreTagVal = scoreTag(grp);
  const scoreTotal = recency + volume + geo + scoreTagVal;
  const country = grp[0].member_country || '';

  const linkedAwards = grp
    .map(m => awardsMap[m.award_id]).filter(Boolean)
    .sort((a,b) => new Date(b.publication_date) - new Date(a.publication_date))
    .slice(0, 3);

  const justification = linkedAwards.map(a => {
    return `[${a.publication_date?.substring(0,7)}] ${String(a.title)}`;
  }).join(' | ');

  const urls = linkedAwards.map(a => a.source_url).filter(Boolean).join(' | ');

  scored.push({ bucket: zone.toUpperCase(), societe: name, pays: country, score_total: scoreTotal, score_recence: recency, score_volume: volume, score_geo: geo, score_tag: scoreTagVal, nb_awards: nAwards, nb_projets: nProjects, dernier_award: lastAward ? lastAward.toISOString().substring(0,7) : 'N/A', justification, urls });
}

// ── Top N par bucket ──
const bucketLimits = { LOCAL: topLocal, REGIONAL: topRegional, INTERNATIONAL: topIntl };
const bucketOrder = { LOCAL: 0, REGIONAL: 1, INTERNATIONAL: 2 };
const bucketCount = {};
const scoredSorted = scored.sort((a,b) => {
  if (a.bucket !== b.bucket) return bucketOrder[a.bucket] - bucketOrder[b.bucket];
  return b.score_total - a.score_total;
});
const scoringRows = [];
for (const row of scoredSorted) {
  const limit = bucketLimits[row.bucket] || 10;
  bucketCount[row.bucket] = (bucketCount[row.bucket] || 0) + 1;
  if (bucketCount[row.bucket] <= limit) scoringRows.push(row);
}

const runDate = new Date().toISOString().substring(0,10);
const stats = {
  total_local: scoredSorted.filter(r => r.bucket === 'LOCAL').length,
  total_regional: scoredSorted.filter(r => r.bucket === 'REGIONAL').length,
  total_international: scoredSorted.filter(r => r.bucket === 'INTERNATIONAL').length,
  retained_local: scoringRows.filter(r => r.bucket === 'LOCAL').length,
  retained_regional: scoringRows.filter(r => r.bucket === 'REGIONAL').length,
  retained_international: scoringRows.filter(r => r.bucket === 'INTERNATIONAL').length,
  experts: experts.length
};

return [{ json: { scoring_rows: scoringRows, experts_rows: experts, sheet_id: sheetId, thematique, thematique_label: criteria.label, pays, run_date: runDate, stats, retained_projects: retainedProjects } }];

const data = $('Scorer & Filtrer').first().json;
return data.experts_rows.map(r => ({ json: {
  Expert: r.expert,
  Pays: r.pays_expert,
  Date_Award: r.date_award,
  Mission: r.mission,
  Valeur: r.valeur,
  Projet_BM: r.projet_bm,
  Méthode: r.methode,
  URL: r.url
}}));

const data = $('Scorer & Filtrer').first().json;
const s = data.stats;
const rows = [
  { Paramètre: 'Thématique', Valeur: `${data.thematique} — ${data.thematique_label}` },
  { Paramètre: 'Pays', Valeur: data.pays },
  { Paramètre: 'Date run', Valeur: data.run_date },
  { Paramètre: '', Valeur: '' },
  { Paramètre: 'LOCAL trouvées', Valeur: s.total_local },
  { Paramètre: 'LOCAL retenues', Valeur: s.retained_local },
  { Paramètre: 'RÉGIONAL trouvées', Valeur: s.total_regional },
  { Paramètre: 'RÉGIONAL retenues', Valeur: s.retained_regional },
  { Paramètre: 'INTERNATIONAL trouvées', Valeur: s.total_international },
  { Paramètre: 'INTERNATIONAL retenues', Valeur: s.retained_international },
  { Paramètre: 'Experts', Valeur: s.experts },
  { Paramètre: '', Valeur: '' },
  { Paramètre: 'PROJETS BM RETENUS', Valeur: '' },
];
for (const p of (data.retained_projects || []).slice(0,10)) {
  rows.push({ Paramètre: p.id, Valeur: `${p.name} (score: ${p.score})` });
}
return rows.map(r => ({ json: r }));
